// src/pages/user/UserPortal.jsx
import React, { useState, useRef, useEffect } from 'react';
import { useApp } from '../../App';
import { GARBAGE_TYPES, AREAS } from '../../data/mockData';
import LiveMap from '../../components/LiveMap'; 

export default function UserPortal() {
  const { addComplaint, complaints } = useApp();
  const videoRef = useRef(null);
  const [capturedImage, setCapturedImage] = useState(null);
  const [gtypeIdx, setGtypeIdx] = useState(0);
  const [area, setArea] = useState(AREAS[0]);
  const [desc, setDesc] = useState('');
  const [statusMsg, setStatusMsg] = useState('');

  const nagpurBaseLat = 21.1522;
  const nagpurBaseLng = 79.0882;

  const activeComplaintsWithCoords = complaints ? complaints.filter(c => c.lat && c.lng) : [];

  useEffect(() => {
    if (!capturedImage) {
      navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' }, audio: false })
        .then(stream => {
          if (videoRef.current) videoRef.current.srcObject = stream;
        })
        .catch(err => {
          console.error("Camera initial mount failed: ", err);
          setStatusMsg('⚠️ Camera access denied or unavailable.');
        });
    }
  }, [capturedImage]);

  const capturePhoto = () => {
    if (!videoRef.current) return;
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth || 640;
    canvas.height = videoRef.current.videoHeight || 480;
    const ctx = canvas.getContext('2d');
    ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
    
    const base64Data = canvas.toDataURL('image/jpeg');
    setCapturedImage(base64Data);
    
    const stream = videoRef.current.srcObject;
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
    }
  };

  const resetCameraLoop = () => {
    setCapturedImage(null);
    setStatusMsg('');
  };

  const handleFormSubmission = (e) => {
    e.preventDefault();
    const gt = GARBAGE_TYPES[gtypeIdx];
    
    addComplaint({
      area,
      gtype: gt.label,
      emoji: gt.emoji,
      severity: gt.severity,
      desc,
      image: capturedImage,
      lat: nagpurBaseLat + (Math.random() - 0.5) * 0.003,
      lng: nagpurBaseLng + (Math.random() - 0.5) * 0.003,
      status: 'NEW' // Explicit mapping for dot color logic consistency
    });

    setDesc('');
    setCapturedImage(null);
    setStatusMsg('✅ Complaint dispatched dynamically into Nagpur Central Command Pipeline!');
    setTimeout(() => setStatusMsg(''), 4500);
  };

  return (
    <div style={{ maxWidth: 480, margin: '20px auto', padding: 16, fontFamily: 'sans-serif', background: '#fff', borderRadius: 16, border: '1px solid #DDE3E9', boxSizing: 'border-box' }}>
      <h3 style={{ margin: '0 0 4px 0', fontSize: 18, fontWeight: 800 }}>📸 Spot-Fix Nagpur Waste App</h3>
      <p style={{ margin: '0 0 16px 0', fontSize: 11, color: '#7A8FA6' }}>Capture real-time garbage snapshots directly on platforms</p>

      {/* 🗺️ STEP 1: MAP ENGINE BLOCK ALWAYS FIRST */}
      <div style={{ marginBottom: 16, borderRadius: 12, overflow: 'hidden', border: '1px solid #DDE3E9' }}>
        <div style={{ padding: '8px 12px', background: '#F7F9FC', borderBottom: '1px solid #DDE3E9', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <span style={{ fontSize: 11, fontWeight: 700, color: '#546E7A' }}> LIVE GEOLOCATION TRACKER</span>
          <span style={{ fontSize: 10, fontFamily: 'monospace', color: '#1565C0', fontWeight: 'bold' }}>LAT: {nagpurBaseLat} · LNG: {nagpurBaseLng}</span>
        </div>
        <LiveMap complaints={activeComplaintsWithCoords} center={[nagpurBaseLat, nagpurBaseLng]} zoom={15} height="180px" />
      </div>

      {statusMsg && (
        <div style={{ padding: 10, background: '#E3F2FD', color: '#1565C0', borderRadius: 8, fontSize: 12, fontWeight: 700, marginBottom: 12, textAlign: 'center' }}>
          {statusMsg}
        </div>
      )}

      {/* 📸 STEP 2: CAMERA STREAM / INPUT SUBMISSION BELOW THE MAP */}
      {!capturedImage ? (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
          <div style={{ width: '100%', height: 240, background: '#000', borderRadius: 12, overflow: 'hidden', position: 'relative' }}>
            <video ref={videoRef} autoPlay playsInline muted style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
          </div>
          <button type="button" onClick={capturePhoto} style={{ background: '#FF1744', color: '#fff', padding: 12, border: 'none', borderRadius: 8, fontWeight: 700, cursor: 'pointer', fontSize: 14 }}>
            📸 CLICK LIVE SNAPSHOT
          </button>
        </div>
      ) : (
        <form onSubmit={handleFormSubmission} style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
          <div style={{ width: '100%', height: 180, borderRadius: 12, overflow: 'hidden', position: 'relative' }}>
            <img src={capturedImage} alt="Target stream map" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
            <button type="button" onClick={resetCameraLoop} style={{ position: 'absolute', top: 8, right: 8, background: 'rgba(0,0,0,0.6)', color: '#fff', border: 'none', padding: '4px 8px', borderRadius: 4, fontSize: 10, cursor: 'pointer', fontWeight: 700 }}>Retake</button>
          </div>

          <div>
            <label style={{ fontSize: 11, fontWeight: 700, color: '#546E7A', display: 'block', marginBottom: 4 }}>STATION REGION LAYER</label>
            <select value={area} onChange={e => setArea(e.target.value)} style={{ width: '100%', padding: 10, borderRadius: 8, border: '1px solid #DDE3E9' }}>
              {AREAS.map(a => <option key={a} value={a}>{a}</option>)}
            </select>
          </div>

          <div>
            <label style={{ fontSize: 11, fontWeight: 700, color: '#546E7A', display: 'block', marginBottom: 4 }}>GARBAGE PROFILE MODEL</label>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 6 }}>
              {GARBAGE_TYPES.map((g, idx) => (
                <div key={g.id} onClick={() => setGtypeIdx(idx)} style={{
                  padding: 10, borderRadius: 8, border: `2px solid ${gtypeIdx === idx ? '#1565C0' : '#DDE3E9'}`,
                  background: gtypeIdx === idx ? '#E3F2FD' : '#fff', cursor: 'pointer', fontSize: 11.5, fontWeight: 700
                }}>{g.emoji} {g.label}</div>
              ))}
            </div>
          </div>

          <div>
            <label style={{ fontSize: 11, fontWeight: 700, color: '#546E7A', display: 'block', marginBottom: 4 }}>ADDITIONAL CONTEXT FIELD</label>
            <input type="text" value={desc} onChange={e => setDesc(e.target.value)} placeholder="e.g. Near coach position indicator pole numbers..." style={{ width: '100%', padding: 10, borderRadius: 8, border: '1px solid #DDE3E9', boxSizing: 'border-box' }} required />
          </div>

          <button type="submit" style={{ background: '#0A1628', color: '#fff', padding: 12, borderRadius: 8, border: 'none', fontWeight: 700, cursor: 'pointer', fontSize: 13, marginTop: 4 }}>
            🚀 TRANSMIT LOG FILE TO HQ
          </button>
        </form>
      )}
    </div>
  );
}
